module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"어린이","note":"어린이 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"회개의 부르심과 환상의 시작","verses":{"krv":[{"n":1,"t":"다리오 왕 이년 팔월에 여호와의 말씀이 잇도의 손자 베레갸의 아들 선지자 스가랴에게 임하니라 가라사대"},{"n":2,"t":"나 여호와가 무리의 열조에게 심히 진노하였느니라"},{"n":3,"t":"그러므로 너는 무리에게 고하기를 만군의 여호와께서 이처럼 이르시되 너희는 내게로 돌아오라 나 만군의 여호와의 말이니라 그리하면 내가 너희에게로 돌아가리라 나 만군의 여호와의 말이니라"},{"n":4,"t":"너희 열조를 본받지 말라 옛적 선지자들이 그들에게 외쳐 가로되 만군의 여호와께서 말씀하시기를 너희가 악한 길, 악한 행실을 떠나서 돌아오라 하셨다 하나 그들이 듣지 않고 내게 귀를 기울이지 아니하였느니라 나 여호와의 말이니라"},{"n":5,"t":"너희 열조가 어디 있느냐 선지자들이 영원히 살겠느냐"},{"n":6,"t":"내가 종 선지자들에게 명한 내 말과 내 전례들이 어찌 네 열조에게 임하지 아니하였느냐 그러므로 그들이 돌쳐 이르기를 만군의 여호와께서 우리 길대로 우리 행위대로 우리에게 행하시려고 뜻하신 것을 우리에게 행하셨도다 하였다 하셨느니라 하라"},{"n":7,"t":"다리오 왕 이년 십일월 곧 스밧월 이십사일에 잇도의 손자 베레갸의 아들 선지자 스가랴에게 여호와의 말씀이 임하여 이르시니라"},{"n":8,"t":"내가 밤에 보니 사람이 홍마를 타고 골짜기 속 화석류나무 사이에 섰고 그 뒤에는 홍마와 자마와 백마가 있기로"},{"n":9,"t":"내가 가로되 내 주여 이들이 무엇이니이까 내게 말하는 천사가 내게 이르되 이들이 무엇인지 내가 네게 보이리라 하매"},{"n":10,"t":"화석류나무 사이에 선 자가 대답하여 가로되 이는 여호와께서 땅에 두루 다니라고 보내신 자들이니라"},{"n":11,"t":"그들이 화석류나무 사이에 선 여호와의 사자에게 고하되 우리가 땅에 두루 다녀보니 온 땅이 평안하여 정온하더이다"},{"n":12,"t":"여호와의 사자가 응하여 가로되 만군의 여호와여 여호와께서 언제까지 예루살렘과 유다 성읍들을 긍휼히 여기지 아니하시려나이까 이를 노하신지 칠십 년이 되었나이다 하매"},{"n":13,"t":"여호와께서 내게 말하는 천사에게 선한 말씀, 위로하는 말씀으로 대답하시더라"},{"n":14,"t":"내게 말하는 천사가 내게 이르되 너는 외쳐 이르기를 만군의 여호와의 말씀에 내가 예루살렘을 위하며 시온을 위하여 크게 질투하며"},{"n":15,"t":"안일한 열국을 심히 진노하나니 나는 조금만 노하였거늘 그들은 힘을 내어 고난을 더하였음이라"},{"n":16,"t":"그러므로 여호와가 이처럼 말하노라 내가 긍휼히 여기므로 예루살렘에 돌아왔은즉 내 집이 그 가운데 건축되리니 예루살렘 위에 먹줄이 치어지리라 나 만군의 여호와의 말이니라 하셨다 하라"},{"n":17,"t":"다시 외쳐 이르기를 만군의 여호와의 말씀에 나의 성읍들이 넘치도록 다시 풍부할 것이라 여호와가 다시 시온을 안위하여 다시 예루살렘을 택하리라 하셨다 하라"},{"n":18,"t":"내가 눈을 들어 본즉 네 뿔이 보이기로"},{"n":19,"t":"이에 내게 말하는 천사에게 묻되 이들이 무엇이니이까 내게 대답하되 이들은 유다와 이스라엘과 예루살렘을 헤친 뿔이니라"},{"n":20,"t":"때에 여호와께서 공장 네 명을 내게 보이시기로"},{"n":21,"t":"내가 가로되 그들이 무엇하러 왔나이까 하매 대답하여 가라사대 그 뿔들이 유다를 헤쳐서 사람으로 능히 머리를 들지 못하게 하매 이 공장들이 와서 그것들을 두렵게 하고 이전에 뿔들을 들어 유다 땅을 헤친 열국의 뿔을 떨어 치려 하느니라 하시더라"}],"kids":[{"n":1,"t":"다리오 왕 이 년 팔월에, 하나님(여호와)의 말씀이 잇도의 손자 베레갸의 아들, 선지자 스가랴에게 임하셨다. 말씀하시기를,"},{"n":2,"t":"\\"나 하나님(여호와)이 너희 무리의 조상들에게 심히 진노하였노라.\\""},{"n":3,"t":"\\"그러므로 너는 무리에게 알려라. 만군의 하나님(여호와)이 이같이 말씀하신다. \\\\\\"너희는 내게로 돌아오라. 나 만군의 하나님(여호와)의 말이라. 그리하면 내가 너희에게로 돌아갈 것이라. 나 만군의 하나님(여호와)의 말이라.\\\\\\"\\""},{"n":4,"t":"\\"너희 조상들을 본받지 말라. 옛적 선지자들이 그들에게 외쳐 \\\\\\"만군의 하나님(여호와)이 말씀하시기를, 너희는 악한 길과 악한 행실을 떠나서 돌아오라\\\\\\"고 하셨으나, 그들이 듣지 않고 내게 귀를 기울이지 아니하였다. 나 하나님(여호와)의 말이라.\\""},{"n":5,"t":"\\"너희 조상들이 어디 있느냐? 선지자들이 영원히 살겠느냐?\\""},{"n":6,"t":"\\"그러나 내가 종 선지자들에게 명한 내 말과 내 율례들이 어찌 너희 조상들에게 이르지 아니하였느냐? 그러므로 그들이 돌이켜 \\\\\\"만군의 하나님(여호와)이 우리 길과 우리 행위대로 우리에게 행하시려고 뜻하신 것을 우리에게 행하셨도다\\\\\\"라고 하였다 하라.\\""},{"n":7,"t":"다리오 왕 이 년 십일월, 곧 스밧월 이십사 일에, 잇도의 손자 베레갸의 아들 선지자 스가랴에게 하나님(여호와)의 말씀이 임하셨다."},{"n":8,"t":"내가 밤에 보니, 한 사람이 붉은 말(홍마)을 타고 골짜기 속의 화석류나무(도금양 나무) 사이에 섰고, 그 뒤에는 붉은 말과 자색 말과 흰 말이 있었다."},{"n":9,"t":"내가 \\"내 주여, 이들이 무엇입니까?\\" 하고 묻자, 내게 말하는 천사가 \\"이들이 무엇인지 내가 네게 보여 주리라\\" 하였다."},{"n":10,"t":"화석류나무 사이에 선 자가 대답하여 말하기를, \\"이들은 하나님(여호와)이 땅에 두루 다니라고 보내신 자들이다\\" 하였다."},{"n":11,"t":"그들이 화석류나무 사이에 선 하나님(여호와)의 사자에게 알리며 말하기를, \\"우리가 땅에 두루 다녀 보니, 온 땅이 평안하고 잠잠하더이다\\" 하였다."},{"n":12,"t":"하나님(여호와)의 사자가 응답하여 말하기를, \\"만군의 하나님(여호와)이여, 하나님(여호와)께서 언제까지 예루살렘과 유다 성읍들을 긍휼히 여기지 아니하시려나이까? 이를 노하신 지 칠십 년이 되었나이다\\" 하였다."},{"n":13,"t":"하나님(여호와)이 내게 말하는 천사에게 선한 말씀, 위로하는 말씀으로 대답하셨다."},{"n":14,"t":"내게 말하는 천사가 내게 말하기를, \\"너는 외쳐 \\\\\\"만군의 하나님(여호와)이 말씀하시기를, 내가 예루살렘을 위하며, 시온을 위하여 크게 질투하며,\\""},{"n":15,"t":"\\"안일한 여러 나라(열국)에게 심히 진노한다. 나는 조금만 노하였거늘, 그들은 힘을 내어 고난을 더하였기 때문이라.\\""},{"n":16,"t":"\\"그러므로 하나님(여호와)이 이같이 말한다. 내가 긍휼히 여기므로 예루살렘에 돌아왔으니, 내 집이 그 가운데 지어질 것이고, 예루살렘 위에 먹줄이 쳐질 것이다. 나 만군의 하나님(여호와)의 말이다\\\\\\" 하셨다 하라.\\""},{"n":17,"t":"\\"다시 외쳐 \\\\\\"만군의 하나님(여호와)이 말씀하시기를, 나의 성읍들이 넘치도록 다시 풍부할 것이라. 하나님(여호와)이 다시 시온을 위로(안위)하여 다시 예루살렘을 택하리라\\\\\\" 하셨다 하라.\\""},{"n":18,"t":"내가 눈을 들어 본즉, 네 뿔이 보였다."},{"n":19,"t":"이에 내가 내게 말하는 천사에게 \\"이들이 무엇입니까?\\"라고 물으니, 그가 내게 대답하기를, \\"이들은 유다와 이스라엘과 예루살렘을 흩어 버린 뿔들이라\\" 하였다."},{"n":20,"t":"그때에 하나님(여호와)이 장인(공장) 네 명을 내게 보이셨다."},{"n":21,"t":"내가 \\"그들이 무엇을 하러 왔습니까?\\"라고 묻자, 그가 대답하시기를, \\"그 뿔들이 유다를 흩어 사람으로 능히 머리를 들지 못하게 하였으므로, 이 장인(공장)들이 와서 그것들을 두렵게 하고, 이전에 뿔들을 들어 유다 땅을 흩어버린 여러 나라(열국)의 뿔을 떨어뜨리려 한다\\" 하셨다."}]}},{"chapter":2,"title":"측량줄을 가진 사람","verses":{"krv":[{"n":1,"t":"내가 또 눈을 들어 본즉 한 사람이 척량줄을 그 손에 잡았기로"},{"n":2,"t":"네가 어디로 가느냐 물은즉 내게 대답하되 예루살렘을 척량하여 그 장광을 보고자 하노라 할 때에"},{"n":3,"t":"내게 말하는 천사가 나가매 다른 천사가 나와서 그를 맞으며"},{"n":4,"t":"이르되 너는 달려가서 그 소년에게 고하여 이르기를 예루살렘에 사람이 거하리니 그 가운데 사람과 육축이 많으므로 그것이 성곽없는 촌락과 같으리라"},{"n":5,"t":"여호와의 말씀에 내가 그 사면에서 불 성곽이 되며 그 가운데서 영광이 되리라"},{"n":6,"t":"여호와의 말씀에 내가 너를 하늘의 사방 바람 같이 흩어지게 하였거니와 이제 너희는 북방 땅에서 도망할지니라 나 여호와의 말이니라"},{"n":7,"t":"바벨론 성에 거하는 시온아 이제 너는 피할지니라"},{"n":8,"t":"만군의 여호와께서 이같이 말씀하시되 너희를 노략한 열국으로 영광을 위하여 나를 보내셨나니 무릇 너희를 범하는 자는 그의 눈동자를 범하는 것이라"},{"n":9,"t":"내가 손을 그들 위에 움직인즉 그들이 자기를 섬기던 자에게 노략거리가 되리라 하셨나니 너희가 만군의 여호와께서 나를 보내신 줄 알리라"},{"n":10,"t":"여호와의 말씀에 시온의 딸아 노래하고 기뻐하라 이는 내가 임하여 네 가운데 거할 것임이니라"},{"n":11,"t":"그 날에 많은 나라가 여호와께 속하여 내 백성이 될 것이요 나는 네 가운데 거하리라 네가 만군의 여호와께서 나를 네게 보내신 줄 알리라"},{"n":12,"t":"여호와께서 장차 유다를 취하여 거룩한 땅에서 자기 소유를 삼으시고 다시 예루살렘을 택하시리니"},{"n":13,"t":"무릇 혈기 있는 자들이 여호와 앞에서 잠잠할 것은 여호와께서 그 성소에서 일어나심이니라 하라 하더라"}],"kids":[{"n":1,"t":"내가 또 눈을 들어 본즉, 한 사람이 측량줄(척량줄)을 그 손에 잡았다."},{"n":2,"t":"내가 \\"네가 어디로 가느냐?\\"고 물었더니, 그가 내게 대답하여 \\"예루살렘을 측량하여 그 길이와 너비(장광)를 알아보려 한다\\" 하였다."},{"n":3,"t":"내게 말하던 천사가 나아가니, 다른 천사가 나와서 그를 맞으며,"},{"n":4,"t":"말하기를, \\"너는 달려가서 그 청년에게 알려 \\\\\\"예루살렘에 사람이 살 것이고, 그 가운데에 사람과 짐승(육축)이 많을 것이므로, 그것이 성곽 없는 마을(촌락) 같을 것이라\\\\\\"고 하라.\\""},{"n":5,"t":"\\"하나님(여호와)이 말씀하셨다. \\\\\\"내가 그 사방에서 불 성곽이 되며, 그 가운데서 영광이 되리라.\\\\\\"\\""},{"n":6,"t":"하나님(여호와)이 말씀하시기를, \\"내가 너희를 하늘의 사방 바람처럼 흩어지게 하였으니, 이제 너희는 북방 땅에서 도망할지니라. 나 하나님(여호와)의 말이라.\\""},{"n":7,"t":"\\"바벨론 성에 사는 시온아, 이제 너는 피할지니라.\\""},{"n":8,"t":"\\"만군의 하나님(여호와)이 이같이 말씀하신다. \\\\\\"너희를 노략한 여러 나라(열국)에 영광을 위해 나를 보내셨으니, 무릇 너희를 범하는 자는 그분의 눈동자를 범하는 것이라.\\""},{"n":9,"t":"\\"\\\\\\"내가 손을 그들 위에 움직이면, 그들이 자기를 섬기던 자에게 노략거리가 되리라\\\\\\"고 하셨다. 너희가 만군의 하나님(여호와)이 나를 보내신 줄 알 것이다.\\""},{"n":10,"t":"\\"하나님(여호와)이 말씀하셨다. \\\\\\"시온의 딸아, 노래하고 기뻐하라. 보라, 내가 임하여 네 가운데 거할 것이다.\\\\\\"\\""},{"n":11,"t":"\\"그날에 많은 나라가 하나님(여호와)께 속하여 내 백성이 될 것이며, 나는 네 가운데 거할 것이다. 네가 만군의 하나님(여호와)이 나를 네게 보내신 줄 알 것이다.\\""},{"n":12,"t":"\\"하나님(여호와)이 장차 유다를 취하여 거룩한 땅에서 자기 소유로 삼으시고, 다시 예루살렘을 택하실 것이다.\\""},{"n":13,"t":"\\"무릇 모든 살아 있는 자(혈기 있는 자)들이 하나님(여호와) 앞에서 잠잠할 것은, 하나님(여호와)이 그 거룩한 처소에서 일어나시기 때문이라\\" 하라."}]}},{"chapter":3,"title":"대제사장 여호수아","verses":{"krv":[{"n":1,"t":"대제사장 여호수아는 여호와의 사자 앞에 섰고 사단은 그의 우편에 서서 그를 대적하는 것을 여호와께서 내게 보이시니라"},{"n":2,"t":"여호와께서 사단에게 이르시되 사단아 여호와가 너를 책망하노라 예루살렘을 택한 여호와가 너를 책망하노라 이는 불에서 꺼낸 그슬린 나무가 아니냐 하실 때에"},{"n":3,"t":"여호수아가 더러운 옷을 입고 천사 앞에 섰는지라"},{"n":4,"t":"여호와께서 자기 앞에 선 자들에게 명하사 그 더러운 옷을 벗기라 하시고 또 여호수아에게 이르시되 내가 네 죄과를 제하여 버렸으니 네게 아름다운 옷을 입히리라 하시기로"},{"n":5,"t":"내가 말하되 정한 관을 그 머리에 씌우소서 하매 곧 정한 관을 그 머리에 씌우며 옷을 입히고 여호와의 사자는 곁에 섰더라"},{"n":6,"t":"여호와의 사자가 여호수아에게 증거하여 가로되"},{"n":7,"t":"만군의 여호와의 말씀에 네가 만일 내 도를 준행하며 내 율례를 지키면 네가 내 집을 다스릴 것이요 내 뜰을 지킬 것이며 내가 또 너로 여기 섰는 자들 중에 왕래케 하리라"},{"n":8,"t":"대제사장 여호수아야 너와 네 앞에 앉은 네 동료들은 내 말을 들을 것이니라 이들은 예표의 사람이라 내가 내 종 순을 나게 하리라"},{"n":9,"t":"만군의 여호와가 말하노라 내가 너 여호수아 앞에 세운 돌을 보라 한 돌에 일곱 눈이 있느니라 내가 새길 것을 새기며 이 땅의 죄악을 하루에 제하리라"},{"n":10,"t":"만군의 여호와가 말하노라 그 날에 너희가 각각 포도나무와 무화과나무 아래로 서로 초대하리라 하셨느니라"}],"kids":[{"n":1,"t":"대제사장 여호수아가 하나님(여호와)의 사자 앞에 섰고, 사단(고발자)이 그의 오른쪽에 서서 그를 대적하는 것을, 하나님(여호와)이 내게 보이셨다."},{"n":2,"t":"하나님(여호와)이 사단에게 말씀하시기를, \\"사단아, 하나님(여호와)이 너를 책망한다. 예루살렘을 택한 하나님(여호와)이 너를 책망한다. 이는 불에서 꺼낸 그슬린 나무 토막이 아니냐?\\" 하셨다."},{"n":3,"t":"여호수아가 더러운 옷을 입고 천사 앞에 서 있었다."},{"n":4,"t":"하나님(여호와)이 자기 앞에 선 자들에게 명하시며 \\"그 더러운 옷을 벗기라\\" 하시고, 또 여호수아에게 \\"내가 네 죄과를 제거하여 버렸으니, 네게 아름다운 옷을 입히리라\\" 하셨다."},{"n":5,"t":"내가 \\"정한 관(터번)을 그 머리에 씌우소서\\" 하니, 곧 정한 관을 그 머리에 씌우며 옷을 입혔다. 하나님(여호와)의 사자는 곁에 서 있었다."},{"n":6,"t":"하나님(여호와)의 사자가 여호수아에게 증거하며 말하기를,"},{"n":7,"t":"\\"만군의 하나님(여호와)이 말씀하셨다. \\\\\\"네가 만일 내 길(도)을 따라 행하며, 내 율례를 지키면, 네가 내 집을 다스릴 것이고, 내 뜰을 지킬 것이며, 내가 또 너로 여기 선 자들 가운데 왕래하게 하리라.\\""},{"n":8,"t":"\\"\\\\\\"대제사장 여호수아야, 너와 네 앞에 앉은 네 동료들은 내 말을 들을지어다. 이들은 예표(미리 보여 주는 표)의 사람들이다. 보라, 내가 내 종 \\\\\'순(가지)\\\\\'을 나게 할 것이다.\\""},{"n":9,"t":"\\"\\\\\\"만군의 하나님(여호와)이 말한다. 내가 너 여호수아 앞에 세운 돌을 보라. 한 돌에 일곱 눈이 있다. 내가 새길 것을 새기며, 이 땅의 죄악을 하루에 제거할 것이다.\\""},{"n":10,"t":"\\"\\\\\\"만군의 하나님(여호와)이 말한다. 그날에 너희가 각각 포도나무와 무화과나무 아래로 서로 초대할 것이라\\\\\\"고 하셨다.\\""}]}},{"chapter":4,"title":"금 등잔대와 두 감람나무","verses":{"krv":[{"n":1,"t":"내게 말하던 천사가 다시 와서 나를 깨우니 마치 자는 사람이 깨우임 같더라"},{"n":2,"t":"그가 내게 묻되 네가 무엇을 보느냐 내가 대답하되 내가 보니 순금 등대가 있는데 그 꼭대기에 주발 같은 것이 있고 또 그 등대에 일곱 등잔이 있으며 그 등대 꼭대기 등잔에는 일곱 관이 있고"},{"n":3,"t":"그 등대 곁에 두 감람나무가 있는데 하나는 그 주발 우편에 있고 하나는 그 좌편에 있나이다 하고"},{"n":4,"t":"내게 말하는 천사에게 물어 가로되 내 주여 이것들이 무엇이니이까"},{"n":5,"t":"내게 말하는 천사가 대답하여 가로되 네가 이것들이 무엇인지 알지 못하느냐 내가 대답하되 내 주여 내가 알지 못하나이다"},{"n":6,"t":"그가 내게 일러 가로되 여호와께서 스룹바벨에게 하신 말씀이 이러하니라 만군의 여호와께서 말씀하시되 이는 힘으로 되지 아니하며 능으로 되지 아니하고 오직 나의 신으로 되느니라"},{"n":7,"t":"큰 산아 네가 무엇이냐 네가 스룹바벨 앞에서 평지가 되리라 그가 머릿돌을 내어 놓을 때에 무리가 외치기를 은총, 은총이 그에게 있을지어다 하리라 하셨고"},{"n":8,"t":"여호와의 말씀이 또 내게 임하여 가라사대"},{"n":9,"t":"스룹바벨의 손이 이 전의 지대를 놓았은즉 그 손이 또한 그것을 마치리라 하셨나니 만군의 여호와께서 나를 너희에게 보내신 줄을 네가 알리라 하셨느니라"},{"n":10,"t":"작은 일의 날이라고 멸시하는 자가 누구냐 이 일곱은 온 세상에 두루 행하는 여호와의 눈이라 다림줄이 스룹바벨의 손에 있음을 보고 기뻐하리라"},{"n":11,"t":"내가 그에게 물어 가로되 등대 좌우의 두 감람나무는 무슨 뜻이니이까 하고"},{"n":12,"t":"다시 그에게 물어 가로되 금 기름을 흘려내는 두 금관 옆에 있는 이 감람나무 두 가지는 무슨 뜻이니이까"},{"n":13,"t":"그가 내게 대답하여 가로되 네가 이것이 무엇인지 알지 못하느냐 대답하되 내 주여 알지 못하나이다"},{"n":14,"t":"가로되 이는 기름 발리운 자 둘이니 온 세상의 주 앞에 모셔 섰는 자니라 하더라"}],"kids":[{"n":1,"t":"내게 말하던 천사가 다시 와서 나를 깨우니, 마치 자던 사람이 깨어남 같았다."},{"n":2,"t":"그가 내게 묻기를, \\"네가 무엇을 보느냐?\\" 하기에, 내가 대답하였다. \\"내가 보니, 순금 등잔대(등대)가 있는데, 그 꼭대기에 주발 같은 것이 있고, 또 그 등잔대에 일곱 등잔이 있으며, 그 등잔대 꼭대기 등잔에는 일곱 관(기름이 흐르는 대롱)이 있고,\\""},{"n":3,"t":"\\"그 등잔대 곁에 두 감람(올리브)나무가 있는데, 하나는 그 주발 오른쪽에, 하나는 그 왼쪽에 있습니다.\\""},{"n":4,"t":"내게 말하는 천사에게 \\"내 주여, 이것들이 무엇입니까?\\"라고 물으니,"},{"n":5,"t":"내게 말하는 천사가 대답하기를, \\"네가 이것들이 무엇인지 알지 못하느냐?\\" 하기에, 내가 \\"내 주여, 알지 못합니다\\"라고 대답하였다."},{"n":6,"t":"그가 내게 일러 말하기를, \\"하나님(여호와)이 스룹바벨에게 하신 말씀이 이러하다. 만군의 하나님(여호와)이 말씀하시기를, \\\\\\"이는 힘으로 되지 아니하며, 능력으로 되지 아니하고, 오직 나의 영(신)으로 되느니라.\\\\\\"\\""},{"n":7,"t":"\\"\\\\\\"큰 산아, 네가 무엇이냐? 네가 스룹바벨 앞에서 평지가 되리라. 그가 머릿돌(맨 위의 돌)을 내어 놓을 때에, 무리가 외치기를 \\\\\'은총, 은총이 그에게 있을지어다\\\\\' 하리라\\\\\\"고 하셨다.\\""},{"n":8,"t":"하나님(여호와)의 말씀이 또 내게 임하여 말씀하셨다."},{"n":9,"t":"\\"스룹바벨의 손이 이 성전의 토대(지대)를 놓았으니, 그의 손이 또한 그것을 마칠 것이다. 만군의 하나님(여호와)이 나를 너희에게 보내신 줄을 네가 알 것이다.\\""},{"n":10,"t":"\\"작은 일의 날이라고 멸시하는 자가 누구냐? 이 일곱은 온 세상에 두루 다니는 하나님(여호와)의 눈이라. 다림줄(반듯하게 재는 줄)이 스룹바벨의 손에 있음을 보고 기뻐할 것이라.\\""},{"n":11,"t":"내가 그에게 묻기를, \\"등잔대 좌우의 두 감람나무는 무슨 뜻입니까?\\" 하고,"},{"n":12,"t":"다시 그에게 묻기를, \\"금 기름을 흘려 내는 두 금관(대롱) 옆에 있는 이 감람나무 두 가지는 무슨 뜻입니까?\\" 하니,"},{"n":13,"t":"그가 내게 대답하여 말하기를, \\"네가 이것이 무엇인지 알지 못하느냐?\\" 하기에, 내가 \\"내 주여, 알지 못합니다\\"라고 대답하였다."},{"n":14,"t":"그가 말하기를, \\"이는 기름 부음을 받은(기름 발리운) 두 사람이니, 온 세상의 주 앞에 모셔 선 자들이라\\" 하였다."}]}},{"chapter":5,"title":"두루마리와 에바의 환상","verses":{"krv":[{"n":1,"t":"내가 다시 눈을 든즉 날아가는 두루마리가 보이더라"},{"n":2,"t":"그가 내게 묻되 네가 무엇을 보느냐 하기로 내가 대답하되 날아가는 두루마리를 보나이다 그 장이 이십 규빗이요 광이 십 규빗이니이다"},{"n":3,"t":"그가 내게 이르되 이는 온 지면에 두루 행하는 저주라 무릇 도적질하는 자는 그 이편 글대로 끊쳐지고 무릇 맹세하는 자는 그 저편 글대로 끊쳐지리라"},{"n":4,"t":"만군의 여호와께서 가라사대 내가 이것을 발하였나니 도적의 집에도 들어가며 내 이름을 가리켜 망령되이 맹세하는 자의 집에도 들어가서 그 집에 머무르며 그 집을 그 나무와 그 돌을 아울러 사르리라 하셨느니라"},{"n":5,"t":"내게 말하던 천사가 나아와서 내게 이르되 너는 눈을 들어 나오는 이것이 무엇인가 보라 하기로"},{"n":6,"t":"내가 묻되 이것이 무엇이니이까 그가 가로되 나오는 이것이 에바니라 또 가로되 온 땅에서 그들의 모양이 이러하니라"},{"n":7,"t":"이 에바 가운데에는 한 여인이 앉았느니라 하는 동시에 둥근 납 한 조각이 들리더라"},{"n":8,"t":"그가 가로되 이는 악이라 하고 그 여인을 에바 속으로 던져 넣고 납 조각을 에바 아구리 위에 던져 덮더라"},{"n":9,"t":"내가 또 눈을 들어 본즉 두 여인이 나왔는데 학의 날개 같은 날개가 있고 그 날개에 바람이 있더라 그들이 그 에바를 천지 사이에 들었기로"},{"n":10,"t":"내가 내게 말하는 천사에게 묻되 그들이 에바를 어디로 옮겨 가나이까 하매"},{"n":11,"t":"내게 이르되 그들이 시날 땅으로 가서 그를 위하여 집을 지으려 함이니라 준공되면 그가 제 처소에 머물게 되리라 하더라"}],"kids":[{"n":1,"t":"내가 다시 눈을 들어보니, 날아가는 두루마리가 보였다."},{"n":2,"t":"그가 내게 묻기를, \\"네가 무엇을 보느냐?\\" 하기에, 내가 대답하기를, \\"날아가는 두루마리를 봅니다. 그 길이가 이십 규빗(약 9미터), 너비(광)가 십 규빗(약 4.5미터)입니다\\" 하였다."},{"n":3,"t":"그가 내게 말하기를, \\"이는 온 지면에 두루 행하는 저주이다. 무릇 도둑질하는 자는 이쪽 글대로 끊어질 것이고, 무릇 거짓 맹세하는 자는 저쪽 글대로 끊어지리라.\\""},{"n":4,"t":"\\"만군의 하나님(여호와)이 말씀하시기를, \\\\\\"내가 이것을 발하였으니, 도둑의 집에도 들어가며, 내 이름을 가리켜 망령되게 맹세하는 자의 집에도 들어가서, 그 집에 머무르며, 그 집을 그 나무와 그 돌까지 다 사르리라\\\\\\"고 하셨다.\\""},{"n":5,"t":"내게 말하던 천사가 나아와서 내게 말하기를, \\"너는 눈을 들어 나오는 이것이 무엇인가 보아라\\" 하기에,"},{"n":6,"t":"내가 \\"이것이 무엇입니까?\\" 하고 물었더니, 그가 말하기를, \\"나오는 이것은 에바(곡식 되는 큰 통)이다\\" 하고, 또 \\"온 땅에서 그들의 모습이 이러하다\\" 하였다."},{"n":7,"t":"이 에바 가운데에 한 여인이 앉아 있었다. 동시에 둥근 납 한 조각이 들렸다."},{"n":8,"t":"그가 말하기를, \\"이는 악이라\\" 하고, 그 여인을 에바 안으로 던져 넣고, 납 조각을 에바 입(아구리) 위에 던져 덮었다."},{"n":9,"t":"내가 또 눈을 들어 본즉, 두 여인이 나왔는데, 학의 날개 같은 날개가 있고, 그 날개에 바람이 있었다. 그들이 그 에바를 하늘과 땅 사이로 들어 올렸다."},{"n":10,"t":"내가 내게 말하는 천사에게 묻기를, \\"그들이 에바를 어디로 옮겨 갑니까?\\" 하니,"},{"n":11,"t":"내게 말하기를, \\"그들이 시날 땅으로 가서 그것을 위해 집을 지으려 함이다. 준공(다 지어지면)되면 그것이 자기 처소에 머물게 될 것이다\\" 하였다."}]}},{"chapter":6,"title":"네 병거의 환상","verses":{"krv":[{"n":1,"t":"내가 또 눈을 들어본즉 네 병거가 두 산 사이에서 나왔는데 그 산은 놋 산이더라"},{"n":2,"t":"첫째 병거는 홍마들이, 둘째 병거는 흑마들이,"},{"n":3,"t":"셋째 벙거는 백마들이, 넷째 병거는 어룽지고 건장한 말들이 메었는지라"},{"n":4,"t":"내가 내게 말하는 천사에게 물어 가로되 내 주여 이것들이 무엇이니이까"},{"n":5,"t":"천사가 대답하여 가로되 이는 하늘의 네 바람인데 온 세상의 주 앞에 모셨다가 나가는 것이라 하더라"},{"n":6,"t":"흑마는 북편 땅으로 나가매 백마의 그 뒤를 따르고 어룽진 말은 남편 땅으로 나가고"},{"n":7,"t":"건장한 말은 나가서 땅에 두루 다니고자 하니 그가 이르되 너희는 여기서 나가서 땅에 두루 다니라 하매 곧 땅에 두루 다니더라"},{"n":8,"t":"그가 외쳐 내게 일러 가로되 북방으로 나간 자들이 북방에서 내 마음을 시원케 하였느니라 하더라"},{"n":9,"t":"여호와의 말씀이 내게 임하여 이르시되"},{"n":10,"t":"사로잡힌 자 중 바벨론에서부터 돌아온 헬대와 도비야와 여다야가 스바냐의 아들 요시아의 집에 들었나니 너는 이 날에 그 집에 들어가서 그들에게서 취하되"},{"n":11,"t":"은과 금을 취하여 면류관을 만들어 여호사닥의 아들 대제사장 여호수아의 머리에 씌우고"},{"n":12,"t":"고하여 이르기를 만군의 여호와께서 말씀하시되 보라 순이라 이름하는 사람이 자기 곳에서 돋아나서 여호와의 전을 건축하리라"},{"n":13,"t":"그가 여호와의 전을 건축하고 영광도 얻고 그 위에 앉아서 다스릴 것이요 또 제사장이 자기 위에 있으리니 이 두 사이에 평화의 의논이 있으리라 하셨다 하고"},{"n":14,"t":"그 면류관은 헬렘과 도비야와 여다야와 스바냐의 아들 헨을 기념하기 위하여 여호와의 전안에 주라 하시니라"},{"n":15,"t":"먼데 사람이 와서 여호와의 전을 건축하리니 만국의 여호와께서 나를 너희에게 보내신 줄을 너희가 알리라 너희가 만일 너희 하나님 여호와의 말씀을 청종할진대 이같이 되리라"}],"kids":[{"n":1,"t":"내가 또 눈을 들어 본즉, 네 병거(전차)가 두 산 사이에서 나왔는데, 그 산은 놋 산(청동 산)이었다."},{"n":2,"t":"첫째 병거는 붉은 말(홍마)들이, 둘째 병거는 검은 말(흑마)들이,"},{"n":3,"t":"셋째 병거는 흰 말(백마)들이, 넷째 병거는 얼룩지고 건장한 말들이 메었다."},{"n":4,"t":"내가 내게 말하는 천사에게 묻기를, \\"내 주여, 이것들이 무엇입니까?\\" 하니,"},{"n":5,"t":"천사가 대답하기를, \\"이는 하늘의 네 바람인데, 온 세상의 주 앞에 모셔 섰다가 나가는 것이다\\" 하였다."},{"n":6,"t":"검은 말은 북쪽 땅으로 나가매, 흰 말은 그 뒤를 따르고, 얼룩진 말은 남쪽 땅으로 나가고,"},{"n":7,"t":"건장한 말은 나가서 땅에 두루 다니고자 하니, 그가 말하기를, \\"너희는 여기서 나가서 땅에 두루 다니라\\" 하니, 곧 땅에 두루 다녔다."},{"n":8,"t":"그가 외쳐 내게 말하기를, \\"북방으로 나간 자들이 북방에서 내 마음을 시원하게 하였다\\" 하였다."},{"n":9,"t":"하나님(여호와)의 말씀이 내게 임하여 말씀하셨다."},{"n":10,"t":"\\"사로잡힌 자 가운데, 바벨론에서부터 돌아온 헬대와 도비야와 여다야가 스바냐의 아들 요시아의 집에 묵었으니, 너는 이 날에 그 집에 들어가서 그들에게서 받되,\\""},{"n":11,"t":"\\"은과 금을 받아 면류관을 만들어, 여호사닥의 아들 대제사장 여호수아의 머리에 씌우고,\\""},{"n":12,"t":"\\"알려 말하기를, 만군의 하나님(여호와)이 말씀하시기를, \\\\\\"보라, 순(가지)이라 이름하는 사람이 자기 곳에서 돋아나서 하나님(여호와)의 전을 지을 것이라.\\""},{"n":13,"t":"\\"\\\\\\"그가 하나님(여호와)의 전을 짓고 영광을 얻으며, 그 위에 앉아 다스릴 것이고, 또 제사장이 자기 위(보좌)에 있을 것이니, 이 둘 사이에 평화의 의논이 있을 것이라\\\\\\"고 하셨다 하고,\\""},{"n":14,"t":"\\"그 면류관은 헬렘과 도비야와 여다야와 스바냐의 아들 헨을 기념하기 위해, 하나님(여호와)의 전 안에 두라\\" 하셨다."},{"n":15,"t":"먼 데 사람이 와서 하나님(여호와)의 전을 지을 것이니, 만군의 하나님(여호와)이 나를 너희에게 보내신 줄을 너희가 알 것이다. 너희가 만일 너희 하나님 하나님(여호와)의 말씀을 청종(잘 들음)할 때, 이같이 될 것이다."}]}},{"chapter":7,"title":"참된 금식","verses":{"krv":[{"n":1,"t":"다리오 왕 사년 구월 곧 기슬래월 사일에 여호와의 말씀이 스가랴에게 임하니라"},{"n":2,"t":"때에 벧엘 사람이 사레셀과 레겜멜렉과 그 종자를 보내어 여호와께 은혜를 구하고"},{"n":3,"t":"만군의 여호와의 전에 있는 제사장들과 선지자들에게 물어 가로되 우리가 여러 해 동안에 행한 대로 오월간에 울며 재계하리이까 하매"},{"n":4,"t":"만군의 여호와의 말씀이 내게 임하여 이르시되"},{"n":5,"t":"온 땅의 백성과 제사장들에게 이르라 너희가 칠십 년 동안 오월과 칠월에 금식하고 애통하였거니와 그 금식이 나를 위하여, 나를 위하여 한 것이냐"},{"n":6,"t":"너희의 먹으며 마심이 전혀 자기을 위하여 먹으며 자기를 위하여 마심이 아니냐"},{"n":7,"t":"여호와가 이전 선지자로 외친 말을 너희가 청종할 것이 아니냐 그 때에는 예루살렘과 사면 읍에 백성이 거하여 형통하였고 남방과 평원에도 사람이 거하였었느니라"},{"n":8,"t":"여호와의 말씀이 스가랴에게 임하여 이르시되"},{"n":9,"t":"만군의 여호와가 이미 말하여 이르기를 너희는 진실한 재판을 행하며 피차에 인애와 긍휼을 베풀며"},{"n":10,"t":"과부와 고아와 나그네와 궁핍한 자를 압제하지 말며 남을 해하려 하여 심중에 도모하지 말라 하였으나"},{"n":11,"t":"그들이 청종하기를 싫어하여 등으로 향하며 듣지 아니하려고 귀를 막으며"},{"n":12,"t":"그 마음을 금강석 같게 하여 율법과 만군의 여호와가 신으로 이전 선지자를 빙자하여 전한 말을 듣지 아니하므로 큰 노가 나 만군의 여호와께로서 나왔도다"},{"n":13,"t":"만군의 여호와가 말하였었노라 내가 불러도 그들이 듣지 아니하였은즉 그들이 불러도 내가 듣지 아니하고"},{"n":14,"t":"회리바람으로 그들을 그 알지 못하던 모든 열국에 헤치리라 한 후로 이 땅이 황무하여 왕래하는 사람이 없었나니 이는 그들이 아름다운 땅으로 황무하게 하였음이니라 하시니라"}],"kids":[{"n":1,"t":"다리오 왕 사 년 구월, 곧 기슬래월 사 일에, 하나님(여호와)의 말씀이 스가랴에게 임하셨다."},{"n":2,"t":"그때에 벧엘 사람이 사레셀과 레겜멜렉과 그 종(종자)을 보내어 하나님(여호와)께 은혜를 구하고,"},{"n":3,"t":"만군의 하나님(여호와)의 전에 있는 제사장들과 선지자들에게 묻기를, \\"우리가 여러 해 동안 행한 대로 오월에도 울며 금식해야 합니까?\\" 하였다."},{"n":4,"t":"만군의 하나님(여호와)의 말씀이 내게 임하여 말씀하셨다."},{"n":5,"t":"\\"온 땅의 백성과 제사장들에게 일러라. 너희가 칠십 년 동안 오월과 칠월에 금식하고 슬퍼하였거니와, 그 금식이 나를 위하여, 나를 위하여 한 것이냐?\\""},{"n":6,"t":"\\"너희가 먹고 마시는 것이 전적으로 자기를 위해 먹고, 자기를 위해 마신 것이 아니냐?\\""},{"n":7,"t":"\\"하나님(여호와)이 이전에 선지자로 외친 말을 너희가 청종해야 할 것이 아니냐? 그 때에는 예루살렘과 사방 읍에 백성이 살아 형통하였고, 남방과 평원에도 사람이 살았었다.\\""},{"n":8,"t":"하나님(여호와)의 말씀이 스가랴에게 임하여 말씀하셨다."},{"n":9,"t":"\\"만군의 하나님(여호와)이 이미 말씀하셨다. \\\\\\"너희는 진실한 재판을 행하며, 서로(피차에) 사랑(인애)과 긍휼을 베풀며,\\""},{"n":10,"t":"\\"\\\\\\"과부와 고아와 나그네와 가난한 자를 압제하지 말며, 남을 해하려고 마음에 도모하지 말라\\\\\\" 하였으나,\\""},{"n":11,"t":"\\"그들이 청종하기를 싫어하여 등을 돌리며, 듣지 않으려고 귀를 막으며,\\""},{"n":12,"t":"\\"그 마음을 금강석(다이아몬드)처럼 굳게 하여, 율법(법)과 만군의 하나님(여호와)이 영(신)으로 이전 선지자를 통해 전한 말을 듣지 않았다. 그러므로 큰 진노가 만군의 하나님(여호와)으로부터 나왔도다.\\""},{"n":13,"t":"\\"만군의 하나님(여호와)이 말씀하셨다. \\\\\\"내가 불러도 그들이 듣지 않았으니, 그들이 불러도 내가 듣지 아니하고,\\""},{"n":14,"t":"\\"\\\\\\"회오리바람으로 그들을 그들이 알지 못하던 모든 여러 나라(열국)에 흩어 버리리라\\\\\\"고 하신 후로, 이 땅이 황폐하여 왕래하는 사람이 없었다. 이는 그들이 아름다운 땅을 황폐하게 하였기 때문이라.\\""}]}},{"chapter":8,"title":"예루살렘의 회복 약속","verses":{"krv":[{"n":1,"t":"만군의 여호와의 말씀이 임하여 이르시되"},{"n":2,"t":"만군의 여호와가 말하노라 내가 시온을 위하여 크게 질투하며 그를 위하여 크게 분노함으로 질투하노라"},{"n":3,"t":"나 여호와가 말하노라 내가 시온에 돌아왔은즉 예루살렘 가운데 거하리니 예루살렘은 진리의 성읍이라 일컫겠고 만군의 여호와의 산은 성산이라 일컫게 되리라"},{"n":4,"t":"만군의 여호와가 말하노라 예루살렘 길거리에 늙은 지아비와 늙은 지어미가 다시 앉을 것이라 다 나이 많으므로 각기 손에 지팡이를 잡을 것이요"},{"n":5,"t":"그 성읍 거리에 동남과 동녀가 가득하여 거기서 장난하리라"},{"n":6,"t":"만군의 여호와가 말하노라 이 일이 그 날에 남은 백성의 눈에는 기이하려니와 내 눈에 어찌 기이하겠느냐 만군의 여호와의 말이니라"},{"n":7,"t":"만군의 여호와가 말하노라 내가 내 백성을 동방에서부터, 서방에서부터 구원하여 내고"},{"n":8,"t":"인도하여다가 예루살렘 가운데 거하게 하리니 그들은 내 백성이 되고 나는 성실과 정의로 그들의 하나님이 되리라"},{"n":9,"t":"만군의 여호와가 말하노라 만군의 여호와의 집 곧 전을 건축하려고 그 지대를 쌓던 날에 일어난 선지자들의 입의 말을 이 때에 듣는 너희는 손을 견고히 할지어다"},{"n":10,"t":"그 날 전에는 사람도 삯을 얻지 못하였고 짐승도 삯을 받지 못하였으며 사람이 대적을 인하여 출입에 평안치 못하였었나니 이는 내가 뭇 사람으로 서로 치게 하였음이어니와"},{"n":11,"t":"만군의 여호와가 말하노니 이제는 내가 이 남은 백성을 대하기를 전일과 같이 아니할 것인즉"},{"n":12,"t":"곧 평안한 추수를 얻을 것이라 포도나무가 열매를 맺으며 땅이 산물을 내며 하늘은 이슬을 내리리니 내가 이 남은 백성으로 이 모든 것을 누리게 하리라"},{"n":13,"t":"유다 족속아 이스라엘 족속아 너희가 이방 가운데서 저주가 되었었으나 이제는 내가 너희를 구원하여 너희로 축복이 되게 하리니 두려워 말지니라 손을 견고히 할지니라"},{"n":14,"t":"만군의 여호와가 말하노라 전에 너희 열조가 나의 노를 격발할 때에 내가 그들에게 재앙을 내리기로 뜻하고 뉘우치지 아니하였었으나"},{"n":15,"t":"이제 내가 예루살렘과 유다 족속에게 은혜를 베풀기로 뜻하였나니 너희는 두려워 말지니라"},{"n":16,"t":"너희가 행할 일은 이러하니라 너희는 각기 이웃으로 더불어 진실을 말하며 너희 성문에서 진실하고 화평한 재판을 베풀고"},{"n":17,"t":"심중에 서로 해하기를 도모하지 말며 거짓 맹세를 좋아하지 말라 이 모든 일은 나의 미워하는 것임이니라 나 여호와의 말이니라"},{"n":18,"t":"만군의 여호와의 말씀이 내게 임하여 이르시되"},{"n":19,"t":"만군의 여호와가 말하노라 사월의 금식과 오월의 금식과 칠월의 금식이 변하여 유다 족속에게 기쁨과 즐거움과 희락의 절기가 되리니 오직 너희는 진실과 화평을 사랑할지니라"},{"n":20,"t":"만군의 여호와가 말하노라 그 후에 여러 백성과 많은 성읍의 거민이 올 것이라"},{"n":21,"t":"이 성읍 거민이 저 성읍에 가서 이르기를 우리가 속히 가서 만군의 여호와를 찾고 여호와께 은혜를 구하자 할 것이면 나도 가겠노라 하겠으며"},{"n":22,"t":"많은 백성과 강대한 나라들이 예루살렘으로 와서 만군의 여호와를 찾고 여호와께 은혜를 구하리라"},{"n":23,"t":"만군의 여호와가 말하노라 그 날에는 방언이 다른 열국 백성 열 명이 유다 사람 하나의 옷자락을 잡을 것이라 곧 잡고 말하기를 하나님이 너희와 함께 하심을 들었나니 우리가 너희와 함께 가려 하노라 하리라 하시니라"}],"kids":[{"n":1,"t":"만군의 하나님(여호와)의 말씀이 임하여 말씀하셨다."},{"n":2,"t":"\\"만군의 하나님(여호와)이 말한다. 내가 시온을 위해 크게 질투하며, 그를 위해 크게 분노함으로 질투하노라.\\""},{"n":3,"t":"\\"나 하나님(여호와)이 말한다. 내가 시온에 돌아왔으니, 예루살렘 가운데 거할 것이라. 예루살렘은 진리의 성읍이라 일컬어지고, 만군의 하나님(여호와)의 산은 거룩한 산이라 일컬어질 것이다.\\""},{"n":4,"t":"\\"만군의 하나님(여호와)이 말한다. 예루살렘 길거리에 늙은 남자(지아비)와 늙은 여자(지어미)가 다시 앉을 것이라. 모두 나이가 많으므로 각기 손에 지팡이를 잡을 것이며,\\""},{"n":5,"t":"\\"그 성읍 거리에 사내아이와 여자아이(동남과 동녀)가 가득하여 거기서 뛰놀(장난할) 것이라.\\""},{"n":6,"t":"\\"만군의 하나님(여호와)이 말한다. 이 일이 그날에 남은 백성의 눈에는 기이하겠으나, 내 눈에 어찌 기이하겠느냐? 만군의 하나님(여호와)의 말이라.\\""},{"n":7,"t":"\\"만군의 하나님(여호와)이 말한다. 내가 내 백성을 동방에서부터, 서방에서부터 구원하여 내고,\\""},{"n":8,"t":"\\"인도하여다가 예루살렘 가운데 거하게 하리니, 그들은 내 백성이 되고, 나는 신실함(성실)과 정의로 그들의 하나님이 될 것이라.\\""},{"n":9,"t":"\\"만군의 하나님(여호와)이 말한다. 만군의 하나님(여호와)의 집, 곧 성전을 짓기 위해 그 토대(지대)를 쌓던 날에 일어난 선지자들의 입의 말을, 이때에 듣는 너희는 손을 견고히 할지어다.\\""},{"n":10,"t":"\\"그날 전에는 사람도 삯을 얻지 못하였고, 짐승도 삯을 받지 못하였으며, 사람이 적 때문에 출입에 평안하지 못하였다. 이는 내가 모든 사람으로 서로 치게 하였기 때문이라.\\""},{"n":11,"t":"\\"만군의 하나님(여호와)이 말한다. 이제는 내가 이 남은 백성을 대하기를 전과 같이 아니할 것이며,\\""},{"n":12,"t":"\\"곧 평안한 추수를 얻을 것이라. 포도나무가 열매를 맺으며, 땅이 산물을 내며, 하늘은 이슬을 내릴 것이니, 내가 이 남은 백성으로 이 모든 것을 누리게 할 것이라.\\""},{"n":13,"t":"\\"유다 족속아, 이스라엘 족속아, 너희가 이방 가운데서 저주가 되었었으나, 이제는 내가 너희를 구원하여 너희로 축복이 되게 할 것이다. 두려워 말지니라. 손을 견고히 할지니라.\\""},{"n":14,"t":"\\"만군의 하나님(여호와)이 말한다. 전에 너희 조상들이 나의 진노를 격발할 때에, 내가 그들에게 재앙을 내리기로 뜻하고 뉘우치지 아니하였으나,\\""},{"n":15,"t":"\\"이제 내가 예루살렘과 유다 족속에게 은혜를 베풀기로 뜻하였으니, 너희는 두려워 말지니라.\\""},{"n":16,"t":"\\"너희가 행할 일은 이러하니라. 너희는 각기 이웃과 더불어 진실을 말하며, 너희 성문에서 진실하고 평화로운(화평한) 재판을 베풀고,\\""},{"n":17,"t":"\\"마음 가운데 서로 해할 것을 도모하지 말며, 거짓 맹세를 좋아하지 말라. 이 모든 일은 내가 미워하는 것이다. 나 하나님(여호와)의 말이라.\\""},{"n":18,"t":"만군의 하나님(여호와)의 말씀이 내게 임하여 말씀하셨다."},{"n":19,"t":"\\"만군의 하나님(여호와)이 말한다. 사월의 금식과 오월의 금식과 칠월의 금식과 시월의 금식이 변하여, 유다 족속에게 기쁨과 즐거움과 즐거운(희락) 절기가 될 것이니, 오직 너희는 진실과 평화(화평)를 사랑할지니라.\\""},{"n":20,"t":"\\"만군의 하나님(여호와)이 말한다. 그 후에 여러 백성과 많은 성읍에 사는 사람들이 올 것이라.\\""},{"n":21,"t":"\\"이 성읍에 사는 사람이 저 성읍에 가서 \\\\\\"우리가 속히 가서 만군의 하나님(여호와)을 찾고, 하나님(여호와)께 은혜를 구하자\\\\\\"고 할 것이며, \\\\\\"나도 가겠노라\\\\\\" 할 것이며,\\""},{"n":22,"t":"\\"많은 백성과 강대한 나라들이 예루살렘으로 와서 만군의 하나님(여호와)을 찾고, 하나님(여호와)께 은혜를 구할 것이라.\\""},{"n":23,"t":"\\"만군의 하나님(여호와)이 말한다. 그날에는 언어가 다른 여러 나라(열국)의 백성 열 명이 유다 사람 한 명의 옷자락을 잡을 것이라. 곧 잡고 말하기를, \\\\\\"하나님이 너희와 함께 하심을 들었으니, 우리가 너희와 함께 가려 하노라\\\\\\" 할 것이라.\\""}]}},{"chapter":9,"title":"왕이 나귀를 타고 오심","verses":{"krv":[{"n":1,"t":"여호와의 말씀의 경고가 하드락 땅에 임하며 다메섹에 머물리니 세상 사람과 이스라엘 모든 지파의 눈이 여호와를 우러러 봄이니라"},{"n":2,"t":"그 접경된 하맛에도 임하겠고 두로와 시돈은 넓은 지혜가 있으니 그들에게도 임하리라"},{"n":3,"t":"두로는 자기를 위하여 보장을 건축하며 은을 티끌 같이, 정금을 거리의 진흙 같이 쌓았은즉"},{"n":4,"t":"주께서 그를 쫓아 내시며 그의 바다 권세를 치시리니 그가 불에 삼키울지라"},{"n":5,"t":"아스글론이 보고 무서워하며 가사도 심히 아파할 것이며 에그론은 그 소망이 수치가 되므로 역시 그러하리라 가사에는 임금이 끊칠 것이며 아스글론에는 거민이 없을 것이며"},{"n":6,"t":"아스돗에는 잡족이 거하리라 내가 블레셋 사람의 교만을 끊고"},{"n":7,"t":"그 입에서 그 피를, 그 잇사이에서 그 가증한 것을 제하리니 그도 남아서 우리 하나님께로 돌아와서 유다의 한 두목 같이 되겠고 에그론은 여부스 사람 같이 되리라"},{"n":8,"t":"내가 내 집을 둘러 진을 쳐서 적군을 막아 거기 왕래하지 못하게 할 것이라 포학한 자가 다시는 그 지경으로 지나지 못하리니 이는 내가 눈으로 친히 봄이니라"},{"n":9,"t":"시온의 딸아 크게 기뻐할지어다 예루살렘의 딸아 즐거이 부를지어다 보라 네 왕이 네게 임하나니 그는 공의로우며 구원을 베풀며 겸손하여서 나귀를 타나니 나귀의 작은 것 곧 나귀새끼니라"},{"n":10,"t":"내가 에브라임의 병거와 예루살렘의 말을 끊겠고 전쟁하는 활도 끊으리니 그가 이방 사람에게 화평을 전할 것이요 그의 정권은 바다에서 바다까지 이르고 유브라데 강에서 땅 끝까지 이르리라"},{"n":11,"t":"또 너로 말할진대 네 언약의 피를 인하여 내가 너의 갇힌 자들을 물 없는 구덩이에서 놓았나니"},{"n":12,"t":"소망을 품은 갇혔던 자들아 너희는 보장으로 돌아올지니라 내가 오늘날도 이르노라 내가 배나 네게 갚을 것이라"},{"n":13,"t":"내가 유다로 당긴 활을 삼고 에브라임으로 먹인 살을 삼았으니 시온아 내가 네 자식을 격동시켜 헬라 자식을 치게 하며 너로 용사의 칼과 같게 하리라"},{"n":14,"t":"여호와께서 그 위에 나타나서 그 살을 번개 같이 쏘아내실 것이며 주 여호와께서 나팔을 불리시며 남방 회리바람을 타고 행하실 것이라"},{"n":15,"t":"만군의 여호와께서 그들을 호위하시리니 그들이 원수를 삼키며 물매돌을 밟을 것이며 그들이 피를 마시고 즐거이 부르기를 술취한 것 같이 할 것인즉 피가 가득한 동이와도 같고 피 묻은 제단 모퉁이와도 같을 것이라"},{"n":16,"t":"이 날에 그들의 하나님 여호와께서 그들을 자기 백성의 양떼 같이 구원하시리니 그들이 면류관의 보석 같이 여호와의 땅에 빛나리로다"},{"n":17,"t":"그의 형통함과 그의 아름다움이 어찌 그리 큰지 소년은 곡식으로 강건하며 처녀는 새 포도주로 그러하리로다"}],"kids":[{"n":1,"t":"하나님(여호와)의 말씀의 경고가 하드락 땅에 임하며, 다메섹에 머물 것이다. 이는 세상 사람과 이스라엘 모든 지파의 눈이 하나님(여호와)을 우러러보기 때문이다."},{"n":2,"t":"그 인접한 하맛에도 임할 것이고, 두로와 시돈은 매우 지혜롭지만, 그들에게도 임할 것이다."},{"n":3,"t":"두로는 자기를 위해 견고한 곳(보장)을 짓고, 은을 티끌처럼, 정금을 거리의 진흙처럼 쌓았으나,"},{"n":4,"t":"주께서 그를 쫓아 내시며, 그의 바다 권세를 치시리니, 그가 불에 삼켜질 것이다."},{"n":5,"t":"아스글론이 보고 무서워하며, 가사도 심히 아파할 것이며, 에그론은 그 소망이 부끄러움(수치)이 되므로 역시 그러할 것이다. 가사에는 임금이 끊어질 것이고, 아스글론에는 사는 사람이 없을 것이며,"},{"n":6,"t":"아스돗에는 잡족이 살 것이다. \\"내가 블레셋 사람의 교만을 끊고,\\""},{"n":7,"t":"\\"그 입에서 그 피를, 그 잇사이에서 그 가증한 것을 제거할 것이라. 그도 살아남아서 우리 하나님께로 돌아와서 유다의 한 우두머리(두목)처럼 될 것이고, 에그론은 여부스 사람처럼 될 것이라.\\""},{"n":8,"t":"\\"내가 내 집을 둘러 진을 쳐서 적군을 막아 거기 왕래하지 못하게 할 것이라. 폭력적인(포학한) 자가 다시는 그 영토(지경)로 지나가지 못할 것이다. 이는 내가 눈으로 친히 보았기 때문이라.\\""},{"n":9,"t":"시온의 딸아, 크게 기뻐할지어다. 예루살렘의 딸아, 즐거이 부를지어다. 보라, 네 왕이 네게 임하시니, 그는 공의로우시며, 구원을 베푸시며, 겸손하셔서 나귀를 타시니, 곧 나귀의 작은 것, 나귀 새끼이로다."},{"n":10,"t":"\\"내가 에브라임의 병거(전차)와 예루살렘의 말을 끊고, 전쟁하는 활도 끊을 것이니, 그가 이방 사람에게 평화(화평)를 전할 것이고, 그의 정권은 바다에서 바다까지 이르고, 유브라데 강에서 땅 끝까지 이를 것이다.\\""},{"n":11,"t":"\\"또 너로 말하자면, 네 언약의 피로 인하여, 내가 너의 갇힌 자들을 물 없는 구덩이에서 풀어주었다.\\""},{"n":12,"t":"\\"소망을 품은 갇혔던 자들아, 너희는 견고한 곳(보장)으로 돌아올지니라. 내가 오늘도 알리노니, 내가 갑절로(배나) 너희에게 갚을 것이라.\\""},{"n":13,"t":"\\"내가 유다로 당긴 활을 삼고, 에브라임으로 메긴(먹인) 화살을 삼았으니, 시온아, 내가 네 자식을 격동시켜 헬라 자식들을 치게 하며, 너로 용사의 칼처럼 되게 할 것이라.\\""},{"n":14,"t":"하나님(여호와)이 그 위에 나타나셔서, 그 화살을 번개처럼 쏘아 내실 것이며, 주 하나님(여호와)이 나팔을 부시며, 남방의 회오리바람을 타고 행하실 것이다."},{"n":15,"t":"만군의 하나님(여호와)이 그들을 호위하실 것이니, 그들이 원수를 삼키며, 물맷돌을 밟을 것이며, 그들이 피를 마시고 즐겁게 부르기를 술 취한 것 같이 할 것이다. 피가 가득한 동이와도 같고, 피 묻은 제단 모퉁이와도 같을 것이다."},{"n":16,"t":"이날에 그들의 하나님 하나님(여호와)이 그들을 자기 백성의 양 떼 같이 구원하실 것이니, 그들이 면류관의 보석 같이 하나님(여호와)의 땅에서 빛날 것이다."},{"n":17,"t":"그분의 형통함과 그분의 아름다움이 어찌 그리 큰지! 청년(소년)은 곡식으로 강건해지며, 처녀는 새 포도주로 그러할 것이로다."}]}},{"chapter":10,"title":"여호와의 자비와 능력","verses":{"krv":[{"n":1,"t":"봄비 때에 여호와 곧 번개를 내는 여호와께 비를 구하라 무리에게 소낙비를 내려서 밭의 채소를 각 사람에게 주리라"},{"n":2,"t":"대저 드라빔들은 허탄한 것을 말하며 복술자는 진실치 않은 것을 보고 거짓꿈을 말한즉 그 위로함이 헛되므로 백성이 양 같이 유리하며 목자가 없으므로 곤고를 당하나니"},{"n":3,"t":"내가 목자들에게 노를 발하며 내가 수염소들을 벌하리라 만군의 여호와가 그 무리 곧 유다 족속을 권고하여 그들로 전쟁의 준마와 같게 하리니"},{"n":4,"t":"모퉁이 돌이 그에게로서, 말뚝이 그에게로서, 싸우는 활이 그에게로서, 권세 잡은 자가 다 일제히 그에게로서 나와서"},{"n":5,"t":"싸울 때에 용사 같이 거리의 진흙 중에 대적을 밟을 것이라 여호와가 그들과 함께한즉 그들이 싸워 말탄 자들로 부끄러워하게 하리라"},{"n":6,"t":"내가 유다 족속을 견고하게 하며 요셉 족속을 구원할지라 내가 그들을 긍휼히 여김으로 그들로 돌아오게 하리니 그들이 내게 내어 버리움이 없었음 같이 되리라 나는 그들의 하나님 여호와라 내가 그들을 들으리라"},{"n":7,"t":"에브라임이 용사 같아서 포도주를 마심 같이 마음이 즐거울 것이요 그 자손은 보고 기뻐하며 여호와를 인하여 마음에 즐거워하리라"},{"n":8,"t":"내가 그들을 향하여 휘파람 불어 모을 것은 내가 그들을 구속하였음이라 그들이 전에 번성하던 것 같이 번성하리라"},{"n":9,"t":"내가 그들을 열방에 뿌리려니와 그들이 원방에서 나를 기억하고 그들의 자녀와 함께 다 생존하여 돌아올지라"},{"n":10,"t":"내가 그들을 애굽 땅에서 이끌어 돌아오며 그들을 앗수르에서부터 모으며 길르앗 땅과 레바논으로 그들을 이끌어 가리니 그 거할 곳이 부족하리라"},{"n":11,"t":"내가 그들로 고해를 지나게 하며 바다 물결을 치리니 나일의 깊은 곳이 다 마르겠고 앗수르의 교만이 낮아지겠고 애굽의 홀이 없어지리라"},{"n":12,"t":"내가 그들로 나 여호와를 의지하여 견고케 하리니 그들이 내 이름을 받들어 왕래하리라 나 여호와의 말이니라"}],"kids":[{"n":1,"t":"봄비 때에 하나님(여호와), 곧 번개를 만드시는 하나님(여호와)께 비를 구하라. 그분이 무리에게 소나기를 내리셔서, 밭의 채소를 각 사람에게 주실 것이다."},{"n":2,"t":"무릇 드라빔(가정의 우상)들은 헛된 것을 말하며, 점쟁이(복술자)는 진실하지 않은 것을 보고 거짓 꿈을 말하니, 그 위로함이 헛되어, 백성이 양처럼 떠돌며, 목자가 없으므로 비참함(곤고)을 당한다."},{"n":3,"t":"\\"내가 목자들에게 진노를 발하며, 숫염소들을 벌할 것이다. 만군의 하나님(여호와)이 그 무리, 곧 유다 족속을 돌아보아(권고하여), 그들로 전쟁의 빠른 말(준마)처럼 되게 할 것이다.\\""},{"n":4,"t":"\\"모퉁이 돌이 그에게서, 말뚝이 그에게서, 싸우는 활이 그에게서, 권세 잡은 자가 다 일제히 그에게서 나와서,\\""},{"n":5,"t":"\\"싸울 때에 용사처럼 거리의 진흙 속의 적을 밟을 것이라. 하나님(여호와)이 그들과 함께 하시니, 그들이 싸워 말 탄 자들을 부끄러움(수치)을 당하게 할 것이다.\\""},{"n":6,"t":"\\"내가 유다 족속을 견고하게 하며, 요셉 족속을 구원할 것이라. 내가 그들을 긍휼히 여겨 그들을 돌아오게 할 것이니, 그들이 내게서 버려진 적이 없는 것 같이 될 것이다. 나는 그들의 하나님 하나님(여호와)이라. 내가 그들의 기도를 들을 것이다.\\""},{"n":7,"t":"\\"에브라임이 용사처럼 되어, 포도주를 마신 것 같이 마음이 즐거울 것이며, 그 자손들은 보고 기뻐하며, 하나님(여호와)으로 인해 마음에 즐거워할 것이라.\\""},{"n":8,"t":"\\"내가 그들을 향해 휘파람을 불어 모을 것은, 내가 그들을 구속하였기 때문이라. 그들이 전에 번성하던 것 같이 번성할 것이라.\\""},{"n":9,"t":"\\"내가 그들을 여러 나라(열방)에 뿌리지만, 그들이 먼 곳(원방)에서 나를 기억하고, 그들의 자녀와 함께 다 살아서 돌아올 것이라.\\""},{"n":10,"t":"\\"내가 그들을 애굽 땅에서 이끌어 돌아오며, 앗수르에서부터 모으며, 길르앗 땅과 레바논으로 그들을 이끌어 갈 것이니, 그 살 곳이 부족할 것이라.\\""},{"n":11,"t":"\\"내가 그들로 고난의 바다(고해)를 지나게 하며, 바닷물결을 치리니, 나일강의 깊은 곳이 다 마를 것이고, 앗수르의 교만이 낮아질 것이며, 애굽의 권세(홀)가 없어질 것이라.\\""},{"n":12,"t":"\\"내가 그들로 나 하나님(여호와)을 의지하여 견고하게 할 것이니, 그들이 내 이름을 받들어 왕래할 것이라. 나 하나님(여호와)의 말이라.\\""}]}},{"chapter":11,"title":"버림받은 목자","verses":{"krv":[{"n":1,"t":"레바논아 네 문을 열고 불이 네 백향목을 사르게 하라"},{"n":2,"t":"너 잣나무여 곡할지어다 백향목이 넘어졌고 아름다운 나무가 훼멸되었도다 바산의 상수리나무여 곡할지어다 무성한 삼림이 엎드러졌도다"},{"n":3,"t":"목자의 곡하는 소리가 남이여 그 영화로운 것이 훼멸되었음이로다 어린 사자의 부르짖는 소리가 남이여 이는 요단의 자랑이 황무하였음이로다"},{"n":4,"t":"여호와 나의 하나님이 가라사대 너는 잡힐 양떼를 먹이라"},{"n":5,"t":"산 자들은 그들을 잡아도 죄가 없다 하고 판 자들은 말하기를 내가 부요케 되었은즉 여호와께 찬송하리라 하고 그 목자들은 그들을 불쌍히 여기지 아니하는도다"},{"n":6,"t":"여호와가 말하노라 내가 다시는 이 땅 거민을 불쌍히 여기지 아니하고 그 사람을 각각 그 이웃의 손과 임금의 손에 붙이리니 그들이 이 땅을 칠지라도 내가 그 손에서 건져내지 아니하리라 하시기로"},{"n":7,"t":"내가 이 잡힐 양떼를 먹이니 참으로 가련한 양이라 내가 이에 막대기 둘을 취하여 하나는 은총이라 하며 하나는 연락이라 하고 양떼를 먹일새"},{"n":8,"t":"한 달 동안에 내가 그 세 목자를 끊었으니 이는 내 마음에 그들을 싫어하였고 그들의 마음에도 나를 미워하였음이라"},{"n":9,"t":"내가 가로되 내가 너희를 먹이지 아니하고 죽는 자는 죽는 대로, 망할 자는 망할 대로, 그 나머지는 피차 살을 먹는 대로 두리라 하고"},{"n":10,"t":"이에 은총이라 하는 막대기를 취하여 잘랐으니 이는 모든 백성과 세운 언약을 폐하려 하였음이라"},{"n":11,"t":"당일에 곧 폐하매 내게 청종하던 가련한 양들은 이것이 여호와의 말씀이었던 줄 안지라"},{"n":12,"t":"내가 그들에게 이르되 너희가 좋게 여기거든 내 고가를 내게 주고 그렇지 아니하거든 말라 그들이 곧 은 삼십을 달아서 내 고가를 삼은지라"},{"n":13,"t":"여호와께서 내게 이르시되 그들이 나를 헤아린바 그 준가를 토기장이에게 던지라 하시기로 내가 곧 그 은 삼십을 여호와의 전에서 토기장이에게 던지고"},{"n":14,"t":"내가 또 연락이라 하는 둘째 막대기를 잘랐으니 이는 유다와 이스라엘 형제의 의를 끊으려 함이었느니라"},{"n":15,"t":"여호와께서 내게 이르시되 너는 또 우매한 목자의 기구들을 취할지니라"},{"n":16,"t":"보라 내가 한 목자를 이 땅에 일으키리니 그가 없어진 자를 마음에 두지 아니하며 흩어진 자를 찾지 아니하며 상한 자를 고치지 아니하며 강건한 자를 먹이지 아니하고 오히려 살진 자의 고기를 먹으며 또 그 굽을 찢으리라"},{"n":17,"t":"화 있을진저 양떼를 버린 못된 목자여 칼이 그 팔에, 우편 눈에 임하리니 그 팔이 아주 마르고 그 우편 눈이 아주 어두우리라"}],"kids":[]}},{"chapter":12,"title":"이스라엘을 위한 보호","verses":{"krv":[{"n":1,"t":"이스라엘에 관한 여호와의 말씀의 경고라 여호와 곧 하늘을 펴시며 땅의 터를 세우시며 사람 안에 심령을 지으신 자가 가라사대"},{"n":2,"t":"보라 내가 예루살렘으로 그 사면 국민에게 혼취케 하는 잔이 되게 할 것이라 예루살렘이 에워싸일 때에 유다에까지 미치리라"},{"n":3,"t":"그 날에는 내가 예루살렘으로 모든 국민에게 무거운 돌이 되게 하리니 무릇 그것을 드는 자는 크게 상할 것이라 천하 만국이 그것을 치려고 모이리라"},{"n":4,"t":"여호와가 말하노라 그 날에 내가 모든 말을 쳐서 놀라게 하며 그 탄 자를 쳐서 미치게 하되 유다 족속은 내가 돌아보고 모든 국민의 말을 쳐서 눈이 멀게 하리니"},{"n":5,"t":"유다의 두목들이 심중에 이르기를 예루살렘 거민이 그들의 하나님 만군의 여호와로 말미암아 힘을 얻었다 할지라"},{"n":6,"t":"그 날에 내가 유다 두목들로 나무 가운데 화로 같게 하며 곡식단 사이에 횃불 같게 하리니 그들이 그 좌우에 에워싼 모든 국민을 사를 것이요 예루살렘 사람은 다시 그 본 곳 예루살렘에 거하게 되리라"},{"n":7,"t":"여호와가 먼저 유다 장막을 구원하리니 이는 다윗의 집의 영광과 예루살렘 거민의 영광이 유다보다 더하지 못하게 하려 함이니라"},{"n":8,"t":"그 날에 여호와가 예루살렘 거민을 보호하리니 그 중에 약한 자가 그 날에는 다윗 같겠고 다윗의 족속은 하나님 같고 무리 앞에 있는 여호와의 사자 같을 것이라"},{"n":9,"t":"예루살렘을 치러 오는 열국을 그 날에 내가 멸하기를 힘쓰리라"},{"n":10,"t":"내가 다윗의 집과 예루살렘 거민에게 은총과 간구하는 심령을 부어 주리니 그들이 그 찌른바 그를 바라보고 그를 위하여 애통하기를 독자를 위하여 애통하듯 하며 그를 위하여 통곡하기를 장자를 위하여 통곡하듯 하리로다"},{"n":11,"t":"그 날에 예루살렘에 큰 애통이 있으리니 므깃도 골짜기 하다드림몬에 있던 애통과 같을 것이라"},{"n":12,"t":"온 땅 각 족속이 따로 애통하되 다윗의 족속이 따로 하고 그 아내들이 따로 하며 나단의 족속이 따로 하고 그 아내들이 따로 하며"},{"n":13,"t":"레위의 족속이 따로 하고 그 아내들이 따로 하며 시므이의 족속이 따로 하고 그 아내들이 따로 하며"},{"n":14,"t":"모든 남은 족속도 각기 따로 하고 그 아내들이 따로 하리라"}],"kids":[]}},{"chapter":13,"title":"찔린 자를 보고 통곡함","verses":{"krv":[{"n":1,"t":"그 날에 죄와 더러움을 씻는 샘이 다윗의 족속과 예루살렘 거민을 위하여 열리리라"},{"n":2,"t":"만군의 여호와가 말하노라 그 날에 내가 우상의 이름을 이 땅에서 끊어서 기억도 되지 못하게 할 것이며 거짓 선지자와 더러운 사귀를 이 땅에서 떠나게 할 것이라"},{"n":3,"t":"사람이 오히려 예언할 것 같으면 그 낳은 부모가 그에게 이르기를 네가 여호와의 이름을 빙자하여 거짓말을 하니 살지 못하리라 하고 낳은 부모가 그 예언할 때에 칼로 찌르리라"},{"n":4,"t":"그 날에 선지자들이 예언할 때에 그 이상을 각기 부끄러워할 것이며"},{"n":5,"t":"말하기를 나는 선지자가 아니요 나는 농부라 내가 어려서부터 사람의 종이 되었노라 할 것이요"},{"n":6,"t":"혹이 그에게 묻기를 네 두 팔 사이에 상처는 어찜이냐 하면 대답하기를 이는 나의 친구의 집에서 받은 상처라 하리라"},{"n":7,"t":"만군의 여호와가 말하노라 칼아 깨어서 내 목자, 내 짝된 자를 치라 목자를 치면 양이 흩어지려니와 작은 자들 위에는 내가 내 손을 드리우리라"},{"n":8,"t":"여호와가 말하노라 이 온 땅에서 삼분지 이는 멸절하고 삼분지 일은 거기 남으리니"},{"n":9,"t":"내가 그 삼분지 일을 불 가운데 던져 은 같이 연단하며 금 같이 시험할 것이라 그들이 내 이름을 부르리니 내가 들을 것이며 나는 말하기를 이는 내 백성이라 할 것이요 그들은 말하기를 여호와는 내 하나님이시라 하리라"}],"kids":[]}},{"chapter":14,"title":"여호와의 날과 그의 통치","verses":{"krv":[{"n":1,"t":"여호와의 날이 이르리라 그 날에 네 재물이 약탈되어 너의 중에서 나누이리라"},{"n":2,"t":"내가 열국을 모아 예루살렘과 싸우게 하리니 성읍이 함락되며 가옥이 약탈되며 부녀가 욕을 보며 성읍 백성이 절반이나 사로잡혀 가려니와 남은 백성은 성읍에서 끊쳐지지 아니하리라"},{"n":3,"t":"그 때에 여호와께서 나가사 그 열국을 치시되 이왕 전쟁 날에 싸운 것 같이 하시리라"},{"n":4,"t":"그 날에 그의 발이 예루살렘 앞 곧 동편 감람 산에 서실 것이요 감람 산은 그 한가운데가 동서로 갈라져 매우 큰 골짜기가 되어서 산 절반은 북으로, 절반은 남으로 옮기고"},{"n":5,"t":"그 산 골짜기는 아셀까지 미칠지라 너희가 그의 산 골짜기로 도망하되 유다 왕 웃시야 때에 지진을 피하여 도망하던 것 같이 하리라 나의 하나님 여호와께서 임하실 것이요 모든 거룩한 자가 주와 함께 하리라"},{"n":6,"t":"그 날에는 빛이 없겠고 광명한 자들이 떠날 것이라"},{"n":7,"t":"여호와의 아시는 한 날이 있으리니 낮도 아니요 밤도 아니라 어두워 갈 때에 빛이 있으리로다"},{"n":8,"t":"그 날에 생수가 예루살렘에서 솟아나서 절반은 동해로, 절반은 서해로 흐를 것이라 여름에도 겨울에도 그러하리라"},{"n":9,"t":"여호와께서 천하의 왕이 되시리니 그 날에는 여호와께서 홀로 하나이실 것이요 그 이름이 홀로 하나이실 것이며"},{"n":10,"t":"온 땅이 아라바 같이 되되 게바에서 예루살렘 남편 림몬까지 미칠 것이며 예루살렘이 높이 들려 그 본처에 있으리니 베냐민 문에서부터 첫문 자리와 성 모퉁이 문까지 또 하나넬 망대에서부터 왕의 포도주 짜는 곳까지라"},{"n":11,"t":"사람이 그 가운데 거하며 다시는 저주가 있지 아니하리니 예루살렘이 안연히 서리로다"},{"n":12,"t":"예루살렘을 친 모든 백성에게 여호와께서 내리실 재앙이 이러하니 곧 섰을 때에 그 살이 썩으며 그 눈이 구멍 속에서 썩으며 그 혀가 입속에서 썩을 것이요"},{"n":13,"t":"그 날에 여호와께서 그들로 크게 요란케 하시리니 피차 손으로 붙잡으며 피차 손을 들어 칠 것이며"},{"n":14,"t":"유다도 예루살렘에서 싸우리니 이 때에 사면에 있는 열국의 보화 곧 금 은과 의복이 심히 많이 모여질 것이요"},{"n":15,"t":"또 말과 노새와 약대와 나귀와 그 진에 있는 모든 육축에게 미칠 재앙도 그 재앙과 같으리라"},{"n":16,"t":"예루살렘을 치러 왔던 열국 중에 남은 자가 해마다 올라와서 그 왕 만군의 여호와께 숭배하며 초막절을 지킬 것이라"},{"n":17,"t":"천하 만국 중에 그 왕 만군의 여호와께 숭배하러 예루살렘에 올라오지 아니하는 자에게는 비를 내리지 아니하실 것인즉"},{"n":18,"t":"만일 애굽 족속이 올라오지 아니할 때에는 창일함이 있지 아니하리니 여호와께서 초막절을 지키러 올라오지 아니하는 열국 사람을 치시는 재앙을 그에게 내리실 것이라"},{"n":19,"t":"애굽 사람이나 열국 사람이나 초막절을 지키러 올라오지 아니하는 자의 받을 벌이 이러하니라"},{"n":20,"t":"그 날에는 말 방울에까지 여호와께 성결이라 기록될 것이라 여호와의 전에 모든 솥이 제단 앞 주발과 다름이 없을 것이니"},{"n":21,"t":"예루살렘과 유다의 모든 솥이 만군의 여호와의 성물이 될 것인즉 제사 드리는 자가 와서 이 솥을 취하여 그 가운데 고기를 삶으리라 그 날에는 만군의 여호와의 전에 가나안 사람이 다시 있지 아니하리라"}],"kids":[]}}]}');

